import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🚀 Dr. Hype — PhD in Product Visibility & Branding (TypeScript)
 * Generated by Sovereign Forge.
 */
export class HypePersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "hype";
        this.name = "Hype";
        this.emoji = "🚀";
        this.role = "PhD Product Evangelist";
        this.phd_identity = "Product Visibility & Branding (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "Fix the following developer experience issue. Simplify confusing APIs, improve error messages, and streamline interfaces. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: ["package.json"],
            rules: [
          {
                    "regex": "\"description\":\\s*\"\"",
                    "issue": "Invisível: package.json sem campo \"description\".",
                    "severity": "medium"
          },
          {
                    "regex": "\"license\":\\s*\"\"",
                    "issue": "Risco Legal: package.json sem campo \"license\".",
                    "severity": "high"
          },
          {
                    "regex": "\"name\":\\s*\"(my-app|project|untitled|test|app)\"",
                    "issue": "Genérico: Nome de pacote genérico impede a identidade do projeto.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Hype operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Hype, PhD em Product Visibility & Branding (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
